      is PlatformRendererType -> {
        stream.write(130)
        writeValue(stream, value.raw.toLong())
      }
      is PlatformMarkerCollisionBehavior -> {
        stream.write(131)
        writeValue(stream, value.raw.toLong())
      }
      is PlatformJointType -> {
        stream.write(132)
        writeValue(stream, value.raw.toLong())
      }
      is PlatformCapType -> {
        stream.write(133)
        writeValue(stream, value.raw.toLong())
      }
      is PlatformPatternItemType -> {
        stream.write(134)
        writeValue(stream, value.raw.toLong())
      }
      is PlatformMarkerType -> {
        stream.write(135)
        writeValue(stream, value.raw.toLong())
      }
      is PlatformMapBitmapScaling -> {
        stream.write(136)
        writeValue(stream, value.raw.toLong())
      }
      is PlatformCameraPosition -> {
        stream.write(137)
        writeValue(stream, value.toList())
      }
      is PlatformCameraUpdate -> {
        stream.write(138)
        writeValue(stream, value.toList())
      }
      is PlatformCameraUpdateNewCameraPosition -> {
        stream.write(139)
        writeValue(stream, value.toList())
      }
      is PlatformCameraUpdateNewLatLng -> {
        stream.write(140)
